"use strict";

const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Normalize tags to lowercase trimmed strings
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (typeof tags === "string") {
    // split by comma and trim
    return tags
      .split(",")
      .map(t => t.trim().toLowerCase())
      .filter(t => t.length > 0);
  }
  if (Array.isArray(tags)) {
    return tags
      .map(t => (typeof t === "string" ? t.trim().toLowerCase() : ""))
      .filter(t => t.length > 0);
  }
  return [];
}

/**
 * Filter problems by difficulty, tags, and limit, preserving stable sorting
 * @param {Object} params
 * @param {string} [params.difficulty] - difficulty filter
 * @param {string|string[]} [params.tags] - tags filter
 * @param {number} [params.limit] - limit number of problems
 * @returns {Object} { problems: Array, metadata: Object }
 */
function getProblems({ difficulty, tags, limit } = {}) {
  let filtered = problemsData;

  if (difficulty) {
    filtered = filtered.filter(
      p => p.difficulty && p.difficulty.toLowerCase() === difficulty.toLowerCase()
    );
  }

  const normalizedTags = normalizeTags(tags);
  if (normalizedTags.length > 0) {
    filtered = filtered.filter(p => {
      if (!p.tags || !Array.isArray(p.tags)) return false;
      const problemTags = p.tags.map(t => t.toLowerCase());
      return normalizedTags.every(t => problemTags.includes(t));
    });
  }

  // stable sort by problem id ascending
  filtered = _.sortBy(filtered, "id");

  if (limit && Number.isInteger(limit) && limit > 0) {
    filtered = filtered.slice(0, limit);
  }

  const metadata = {
    total: filtered.length,
    difficulty: difficulty || null,
    tags: normalizedTags,
    limit: limit || null,
  };

  return { problems: filtered, metadata };
}

module.exports = {
  normalizeTags,
  getProblems,
};
